# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import pandas as pd
import tensorflow as tf
from tensorflow.keras import layers, models
import os

app = Flask(__name__)

# Directory to store uploaded training files
UPLOAD_FOLDER = 'uploads/'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Global variable for the model
model = None

def create_model(input_shape, num_classes):
    model = models.Sequential()
    model.add(layers.Conv2D(32, (3, 3), activation='relu', input_shape=input_shape))
    model.add(layers.MaxPooling2D((2, 2)))
    model.add(layers.Conv2D(64, (3, 3), activation='relu'))
    model.add(layers.MaxPooling2D((2, 2)))
    model.add(layers.Conv2D(64, (3, 3), activation='relu'))
    model.add(layers.Flatten())
    model.add(layers.Dense(64, activation='relu'))
    model.add(layers.Dense(num_classes, activation='softmax'))
    return model

def train_model(csv_file, image_folder):
    data = pd.read_csv(csv_file)
    images = []  # Load images based on paths in CSV
    labels = []  # Add corresponding labels
    for index, row in data.iterrows():
        img_path = os.path.join(image_folder, row['image_filename'])
        image = tf.keras.preprocessing.image.load_img(img_path, target_size=(150, 150))
        image_array = tf.keras.preprocessing.image.img_to_array(image)
        images.append(image_array)
        labels.append(row['label'])
    
    images = tf.convert_to_tensor(images)
    labels = tf.convert_to_tensor(labels)

    model.fit(images, labels, epochs=10)

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})

    filename = os.path.join(UPLOAD_FOLDER, file.filename)
    file.save(filename)

    if filename.endswith('.csv'):
        train_model(filename, UPLOAD_FOLDER)

    return jsonify({'success': True})

@app.route('/initialize_model', methods=['POST'])
def initialize_model():
    global model
    input_shape = (150, 150, 3)  # Example input shape for images
    num_classes = 10  # Change to your number of classes
    model = create_model(input_shape, num_classes)
    return jsonify({'model_initialized': True})

if __name__ == '__main__':
    app.run(debug=True)